import tensorflow as tfimport cv2img = cv2.imread('images/3.png', 0)print(type(img), img.shape)ret, img = cv2.threshold(img, 150, 255, cv2.THRESH_BINARY_INV)cv2.imshow('img', img)cv2.waitKey()img = cv2.resize(img, (28, 28))img = img.reshape(1, 784)print(img.shape)new_model = tf.keras.models.load_model('./model/model.h5', compile=False)predict = new_model.predict(img)print(tf.argmax(predict, 1), predict.shape)